#include <stdio.h>
#include <string.h>

int max(int a, int b) { return a > b ? a : b; }

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char s[101];
    getchar(); // consume newline after T
    while (T--) {
        if (!fgets(s, sizeof(s), stdin)) break;
        s[strcspn(s, "\n")] = '\0'; // remove trailing newline
        int n = strlen(s);
        char r[101];
        for (int i = 0; i < n; ++i) r[i] = s[n - 1 - i];
        r[n] = '\0';
        static int dp[101][101];
        for (int i = 0; i <= n; ++i) dp[i][0] = dp[0][i] = 0;
        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= n; ++j) {
                if (s[i-1] == r[j-1]) dp[i][j] = dp[i-1][j-1] + 1;
                else dp[i][j] = max(dp[i-1][j], dp[i][j-1]);
            }
        }
        printf("%d\n", dp[n][n]);
    }
    return 0;
}

